   123→    <script>
   124→        // ========================================
   125→        // MACRO LAYER - Heatmap
   126→        // ========================================
   127→        function initMacroLayer() {
   128→            const canvas = document.getElementById('macroCanvas');
   129→            const ctx = canvas.getContext('2d');
   130→            const container = canvas.parentElement;
   131→
   132→            // Set canvas size
   133→            function resize() {
   134→                canvas.width = container.clientWidth;
   135→                canvas.height = container.clientHeight - 20;
   136→                renderMacro();
   137→            }
   138→
   139→            // Generate heatmap data
   140→            const years = ['Jan 2021', 'Mey 2021', 'Jan 2031', 'Jan 2031', 'Nov 2032', 'Jan 2032', 'Mar 2032', 'Jun 2030', 'Dec 2031', 'Jan 2032', 'Mar 2033', 'Jul 2033'];
   141→            const trains = ['2039', '2030', '2031', '2032', '2033', '2034', '2035', '2036', '2037', '2038', '2039', '2032'];
   142→
   143→            // Populate axes
   144→            document.getElementById('macroYAxis').innerHTML = trains.map(t => `<span class="block text-center">${t}</span>`).join('');
   145→            document.getElementById('macroXAxis').innerHTML = years.map(y => `<span class="px-1">${y}</span>`).join('');
   146→
   147→            // Noise function for organic heatmap
   148→            function noise(x, y, seed) {
   149→                const n = Math.sin(x * 12.9898 + y * 78.233 + seed) * 43758.5453;
   150→                return n - Math.floor(n);
   151→            }
   152→
   153→            function smoothNoise(x, y, seed) {
   154→                const x0 = Math.floor(x), y0 = Math.floor(y);
   155→                const fx = x - x0, fy = y - y0;
   156→                const v00 = noise(x0, y0, seed);
   157→                const v10 = noise(x0 + 1, y0, seed);
   158→                const v01 = noise(x0, y0 + 1, seed);
   159→                const v11 = noise(x0 + 1, y0 + 1, seed);
   160→                const i1 = v00 * (1 - fx) + v10 * fx;
   161→                const i2 = v01 * (1 - fx) + v11 * fx;
   162→                return i1 * (1 - fy) + i2 * fy;
   163→            }
   164→
   165→            function fbm(x, y, seed) {
   166→                let value = 0, amplitude = 0.5;
   167→                for (let i = 0; i < 4; i++) {
   168→                    value += amplitude * smoothNoise(x, y, seed);
   169→                    x *= 2; y *= 2;
   170→                    amplitude *= 0.5;
   171→                }
   172→                return value;
   173→            }
   174→
   175→            // Color interpolation
   176→            function getHeatColor(value) {
   177→                // Yellow -> Orange -> Red gradient
   178→                if (value < 0.3) {
   179→                    return `rgb(255, ${Math.floor(243 - value * 100)}, ${Math.floor(196 - value * 300)})`;
   180→                } else if (value < 0.6) {
   181→                    const t = (value - 0.3) / 0.3;
   182→                    return `rgb(255, ${Math.floor(180 - t * 80)}, ${Math.floor(100 - t * 80)})`;
   183→                } else {
   184→                    const t = (value - 0.6) / 0.4;
   185→                    return `rgb(${Math.floor(255 - t * 55)}, ${Math.floor(100 - t * 70)}, ${Math.floor(20 + t * 20)})`;
   186→                }
   187→            }
   188→
   189→            function renderMacro() {
   190→                const w = canvas.width;
   191→                const h = canvas.height;
   192→                const cellW = 6;
   193→                const cellH = 6;
   194→
   195→                // Create concentrated hotspots (dark red blobs) like in the design
   196→                const hotspots = [
   197→                    // Right side - main concentration area (like in design)
   198→                    { x: 0.72, y: 0.25, radius: 0.08, intensity: 1.0 },
   199→                    { x: 0.78, y: 0.35, radius: 0.10, intensity: 1.0 },
   200→                    { x: 0.85, y: 0.45, radius: 0.12, intensity: 1.0 },
   201→                    { x: 0.80, y: 0.55, radius: 0.09, intensity: 1.0 },
   202→                    { x: 0.88, y: 0.65, radius: 0.11, intensity: 1.0 },
   203→                    { x: 0.75, y: 0.75, radius: 0.08, intensity: 0.9 },
   204→                    // Some scattered smaller hotspots
   205→                    { x: 0.45, y: 0.30, radius: 0.05, intensity: 0.6 },
   206→                    { x: 0.50, y: 0.50, radius: 0.06, intensity: 0.5 },
   207→                    { x: 0.55, y: 0.70, radius: 0.05, intensity: 0.5 },
   208→                ];
   209→
   210→                // Gaussian function for smooth blob falloff
   211→                function gaussian(x, y, cx, cy, radius) {
   212→                    const dx = x - cx;
   213→                    const dy = y - cy;
   214→                    const d2 = (dx * dx + dy * dy) / (radius * radius);
   215→                    return Math.exp(-d2 * 2);
   216→                }
   217→
   218→                for (let x = 0; x < w; x += cellW) {
   219→                    for (let y = 0; y < h; y += cellH) {
   220→                        const nx = x / w;
   221→                        const ny = y / h;
   222→
   223→                        // Base noise for texture
   224→                        let value = fbm(nx * 10, ny * 8, 42) * 0.25;
   225→
   226→                        // Add gaussian blob influence from each hotspot
   227→                        hotspots.forEach(hs => {
   228→                            const blobValue = gaussian(nx, ny, hs.x, hs.y, hs.radius) * hs.intensity;
   229→                            value += blobValue * 0.75;
   230→                        });
   231→
   232→                        // Add subtle noise texture
   233→                        value += noise(x * 0.5, y * 0.5, 123) * 0.08;
   234→                        value = Math.min(1, Math.max(0, value));
   235→
   236→                        ctx.fillStyle = getHeatColor(value);
   237→                        ctx.fillRect(x, y, cellW - 1, cellH - 1);
   238→                    }
   239→                }
   240→
   241→                // Draw selection rectangle
   242→                ctx.strokeStyle = '#64748b';
   243→                ctx.lineWidth = 2;
   244→                ctx.strokeRect(w * 0.68, 10, w * 0.25, h - 20);
   245→            }
   246→
   247→            resize();
   248→            window.addEventListener('resize', resize);
   249→        }
   250→
   251→        // ========================================
   252→        // MESO LAYER - DNA Strip
   253→        // ========================================
   254→        function initMesoLayer() {
   255→            const canvas = document.getElementById('mesoCanvas');
   256→            const ctx = canvas.getContext('2d');
   257→            const container = canvas.parentElement;
   258→
   259→            // Months for x-axis
   260→            const months = ['Jul 1', 'Sep', 'Oct', 'Nov', 'Dec', '2032', 'Feb', 'Mar', 'Apr', 'May', 'Jun', '2032', 'Mar', 'Sep', 'SiO3'];
   261→
   262→            document.getElementById('mesoXAxis').innerHTML = months.map((m, i) =>
   263→                `<span class="px-2 ${m === '2032' ? 'bg-blue-100 font-semibold text-blue-700 rounded' : ''}">${m}</span>`
   264→            ).join('');
   265→
   266→            function resize() {
   267→                canvas.width = container.clientWidth;
   268→                canvas.height = container.clientHeight - 24;
   269→                renderMeso();
   270→            }
   271→
   272→            function renderMeso() {
   273→                const w = canvas.width;
   274→                const h = canvas.height;
   275→
   276→                ctx.fillStyle = '#f8f9fa';
   277→                ctx.fillRect(0, 0, w, h);
   278→
   279→                // Draw diagonal DNA strips
   280→                const stripHeight = 12;
   281→                const stripGap = 2;
   282→                const numRows = Math.floor(h / (stripHeight + stripGap));
   283→                const stripWidth = 60;
   284→                const angle = -30 * Math.PI / 180;
   285→
   286→                for (let row = 0; row < numRows; row++) {
   287→                    const y = row * (stripHeight + stripGap) + 30;
   288→
   289→                    // Stagger start position based on row
   290→                    const startOffset = (row * 25) % 100;
   291→
   292→                    for (let x = -100 + startOffset; x < w + 200; x += stripWidth + 15) {
   293→                        // Alternate colors - orange and blue
   294→                        const isOrange = (Math.floor(x / 80) + row) % 3 !== 0;
   295→
   296→                        ctx.save();
   297→                        ctx.translate(x, y);
   298→                        ctx.rotate(angle);
   299→
   300→                        // Draw strip
   301→                        const gradient = ctx.createLinearGradient(0, 0, stripWidth, 0);
   302→                        if (isOrange) {
   303→                            gradient.addColorStop(0, '#f59e0b');
   304→                            gradient.addColorStop(1, '#d97706');
   305→                        } else {
   306→                            gradient.addColorStop(0, '#3b82f6');
   307→                            gradient.addColorStop(1, '#1d4ed8');
   308→                        }
   309→
   310→                        ctx.fillStyle = gradient;
   311→                        ctx.beginPath();
   312→                        ctx.roundRect(0, 0, stripWidth, stripHeight, 2);
   313→                        ctx.fill();
   314→
   315→                        ctx.restore();
   316→                    }
   317→                }
   318→
   319→                // Draw highlighted selection area
   320→                ctx.strokeStyle = '#93c5fd';
   321→                ctx.lineWidth = 2;
   322→                ctx.fillStyle = 'rgba(147, 197, 253, 0.1)';
   323→                ctx.fillRect(w * 0.35, 0, w * 0.15, h);
   324→                ctx.strokeRect(w * 0.35, 0, w * 0.15, h);
   325→            }
   326→
   327→            resize();
   328→            window.addEventListener('resize', resize);
   329→        }
   330→
   331→        // ========================================
   332→        // MICRO LAYER - Detailed Gantt
