   334→        function initMicroLayer() {
   335→            const ganttHeader = document.getElementById('ganttHeader');
   336→            const ganttBody = document.getElementById('ganttBody');
   337→            const wrapper = document.getElementById('ganttWrapper');
   338→            const svg = document.getElementById('dependencyCanvas');
   339→            const tooltip = document.getElementById('tooltip');
   340→
   341→            // Generate dates for header
   342→            const dates = [];
   343→            const startDate = new Date(2032, 2, 1); // March 2032
   344→            for (let i = 0; i < 40; i++) {
   345→                const d = new Date(startDate);
   346→                d.setDate(d.getDate() + i);
   347→                dates.push(d);
   348→            }
   349→
   350→            // Render header
   351→            ganttHeader.innerHTML = dates.map(d => {
   352→                const day = d.getDate();
   353→                const month = d.toLocaleDateString('en', { month: 'short' });
   354→                return `<div class="flex-1 min-w-[50px] flex flex-col items-center justify-center text-[10px] text-gray-500 border-r border-gray-100">
   355→                    <span>${day} ${month}</span>
   356→                    <span class="text-[9px] text-gray-400">March 2032</span>
   357→                </div>`;
   358→            }).join('');
   359→
   360→            // Task data
   361→            const tasks = [
   362→                { id: 1, name: 'Bogie Overhaul Campaign | T145, T146', x: 20, y: 20, width: 200, color: 'orange', row: 0 },
   363→                { id: 2, name: 'Bogie Overhaul Campaign', x: 60, y: 50, width: 180, color: 'blue', row: 1 },
   364→                { id: 3, name: 'Heavy Lift Crane', x: 100, y: 80, width: 120, color: 'gray', row: 2 },
   365→                { id: 4, name: 'Techs Pit 1 & 3', x: 120, y: 110, width: 100, color: 'blue', row: 3 },
   366→                { id: 5, name: 'Bogie Overhaul Campaign | T145', x: 180, y: 140, width: 170, color: 'blue', row: 4 },
   367→                { id: 6, name: 'Bogie Overhaul Campaign', x: 220, y: 170, width: 160, color: 'blue', row: 5 },
   368→                { id: 7, name: 'Bogie Overhaul Campaign', x: 260, y: 200, width: 150, color: 'blue', row: 6 },
   369→                { id: 8, name: 'Bogie Overhaul Campaign', x: 300, y: 230, width: 160, color: 'blue', row: 7 },
   370→                { id: 9, name: 'Bogie Overhaul Campaign', x: 340, y: 260, width: 150, color: 'blue', row: 8 },
   371→                { id: 10, name: 'Techs Pit Campaign', x: 380, y: 290, width: 130, color: 'gray', row: 9 },
   372→                { id: 11, name: 'Techs Pit Full snape', x: 420, y: 320, width: 140, color: 'blue', row: 10 },
   373→                { id: 12, name: 'Techs Pit & &', x: 460, y: 350, width: 100, color: 'blue', row: 11 },
   374→                { id: 13, name: 'Techs Pit Sick saips', x: 500, y: 380, width: 130, color: 'orange', row: 12 },
   375→
   376→                // Middle section
   377→                { id: 14, name: 'Heavy Lift Crane', x: 520, y: 20, width: 120, color: 'gray', row: 0 },
   378→                { id: 15, name: 'Bogie Overhaul Campaign', x: 540, y: 50, width: 180, color: 'blue', row: 1 },
   379→                { id: 16, name: 'Bogie Overhaul Campaign | T145, T146', x: 600, y: 80, width: 200, color: 'blue', row: 2 },
   380→                { id: 17, name: 'Bogie Overhaul Campaign | T145, T146, T147', x: 640, y: 110, width: 220, color: 'blue', row: 3 },
   381→                { id: 18, name: 'Techs, Pit', x: 680, y: 140, width: 80, color: 'gray', row: 4 },
   382→                { id: 19, name: 'Bogie Overhaul Campaign | T145, T146, T147', x: 720, y: 170, width: 230, color: 'orange', hasConflict: true, row: 5 },
   383→                { id: 20, name: 'Bogie Overhaul Campaign | T145, T146, T147', x: 760, y: 200, width: 220, color: 'blue', row: 6 },
