   394→                { id: 29, name: 'Bogie Overhaul Campaign | T145, T146, T147', x: 1180, y: 170, width: 240, color: 'blue', row: 5 },
   395→                { id: 30, name: 'Bogie Overhaul Campaign |', x: 1220, y: 200, width: 180, color: 'blue', row: 6 },
   396→                { id: 31, name: 'Bogie Overhaul Campaign', x: 1260, y: 230, width: 160, color: 'orange', row: 7 },
